// JavaScript — runtime error (no warning at all):
function add(a, b) {
  return a + b;
}
add('5', 3); // '53' — string concatenation, not addition. Bug silently.

// TypeScript — caught at compile time:
function add(a: number, b: number): number {
  return a + b;
}
add('5', 3);
// ❌ Error: Argument of type 'string' is not assignable to parameter of type 'number'

// Type inference — no annotation needed:
const name = 'Alice';    // inferred as: string
const age = 30;          // inferred as: number
const items = [1, 2, 3]; // inferred as: number[]

// Compiles to plain JS — types are erased:
// function add(a, b) { return a + b; }
// All type safety exists ONLY at compile time

// Interface — extendable, mergeable
interface User {
  id: string;
  name: string;
  email: string;
}

interface AdminUser extends User {
  permissions: string[];
}

// Declaration merging — adding to an existing interface:
interface User {
  createdAt: Date; // merged into the original User interface
}

// Type alias — unions, intersections, complex types
type ID = string | number; // Union — can't do this with interface
type Nullable<T> = T | null;
type Callback = (event: MouseEvent) => void;
type Point = { x: number; y: number };

// Intersection — combine multiple types:
type AdminUser = User & { permissions: string[] };

// Structural typing — TypeScript checks shape, not name:
interface Named { name: string; }
function greet(obj: Named) { console.log(obj.name); }

const user = { name: 'Alice', age: 30 };
greet(user); // ✅ Works! user has 'name', extra props are fine

// Tuple type:
type Pair = [string, number];
const entry: Pair = ['age', 30]; // ✅
const bad: Pair  = [30, 'age']; // ❌ Order matters

// any — dangerous
let val: any = 'hello';
val.toFixed(2); // No error — TS can't help you here

// unknown — safe
let val2: unknown = 'hello';
val2.toFixed(2); // ❌ Error: Object is of type 'unknown'
// Must narrow first:
if (typeof val2 === 'string') {
  val2.toUpperCase(); // ✅ TS knows it's a string here
}

// never — exhaustive checks
type Shape = 'circle' | 'square';
function area(s: Shape): number {
  switch (s) {
    case 'circle': return Math.PI;
    case 'square': return 1;
    default:
      const _exhaustive: never = s; // ❌ Error if Shape adds 'triangle' but we forget to handle it
      throw new Error('Unhandled shape');
  }
}

// Literal types — narrow string/number to specific values
type Direction = 'up' | 'down' | 'left' | 'right';
type HTTPStatus = 200 | 201 | 400 | 404 | 500;
type Flags = { readonly debug: true; env: 'prod' | 'dev' };

// Type narrowing — 'in' operator
interface Cat { meow(): void; }
interface Dog { bark(): void; }
function speak(animal: Cat | Dog) {
  if ('meow' in animal) {
    animal.meow(); // TS knows it's Cat here
  } else {
    animal.bark(); // TS knows it's Dog here
  }
}

// Without generics — forced to use any or overloads:
function identity(arg: any): any { return arg; } // loses type info

// With generics — type is preserved:
function identity<T>(arg: T): T { return arg; }
const str = identity('hello');  // T = string, returns string
const num = identity(42);       // T = number, returns number

// Generic with constraint — T must have 'length'
function logLength<T extends { length: number }>(arg: T): T {
  console.log(arg.length);
  return arg;
}
logLength('hello');   // ✅ strings have length
logLength([1, 2, 3]); // ✅ arrays have length
logLength(42);        // ❌ numbers don't have length

// Generic interface
interface ApiResponse<T> {
  data: T;
  status: number;
  message: string;
}
type UserResponse = ApiResponse<User>;   // data: User
type ListResponse = ApiResponse<User[]>; // data: User[]

// Keyof constraint — accessing object properties safely
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key]; // T[K] = the exact type of that property
}
const user = { name: 'Alice', age: 30 };
const name = getProperty(user, 'name'); // type: string ✅
getProperty(user, 'height');            // ❌ 'height' doesn't exist

// ReturnType — extract what a function returns
function createUser() {
  return { id: '1', name: 'Alice', createdAt: new Date() };
}
type User = ReturnType<typeof createUser>;
// User = { id: string; name: string; createdAt: Date }
// No duplication — if createUser changes, User type updates automatically!

// Parameters — extract function params as tuple
function login(email: string, password: string, rememberMe?: boolean) {}
type LoginParams = Parameters<typeof login>;
// LoginParams = [email: string, password: string, rememberMe?: boolean]

// infer — extract type in conditional type
type UnpackPromise<T> = T extends Promise<infer U> ? U : T;
type A = UnpackPromise<Promise<string>>;  // string
type B = UnpackPromise<Promise<User[]>>;  // User[]
type C = UnpackPromise<number>;           // number (not a Promise, returns T)

// infer for array element type:
type ArrayElement<T> = T extends (infer U)[] ? U : never;
type X = ArrayElement<string[]>;  // string
type Y = ArrayElement<number[]>;  // number

// Practical: extract event handler param type:
type EventParam<T extends (e: any) => any> = T extends (e: infer E) => any ? E : never;
type ClickEvent = EventParam<React.MouseEventHandler<HTMLButtonElement>>;
// ClickEvent = React.MouseEvent<HTMLButtonElement, MouseEvent>

interface User {
  id: string;
  name: string;
  email: string;
  age: number;
  role: 'admin' | 'user';
}

// Partial — all optional (for update payloads)
type UserUpdate = Partial<User>;
// { id?: string; name?: string; email?: string; ... }

// Required — all required (opposite of Partial)
type RequiredUser = Required<User>; // removes all ?

// Pick — select fields (for DTOs, API responses)
type UserPreview = Pick<User, 'id' | 'name'>;
// { id: string; name: string }

// Omit — exclude fields (hide sensitive data)
type PublicUser = Omit<User, 'email' | 'age'>;
// { id: string; name: string; role: ... }

// Record — typed dictionary
type RolePermissions = Record<User['role'], string[]>;
const perms: RolePermissions = {
  admin: ['read', 'write', 'delete'],
  user: ['read'],
};

// Exclude / Extract — manipulate union types
type Status = 'pending' | 'active' | 'deleted';
type ActiveStatus = Exclude<Status, 'deleted'>; // 'pending' | 'active'
type OnlyActive = Extract<Status, 'active' | 'archived'>; // 'active'

// NonNullable
type MaybeString = string | null | undefined;
type SafeString = NonNullable<MaybeString>; // string

// Without 'as const' — types are widened
const config = { env: 'prod', port: 3000 };
// type: { env: string; port: number } — loses the literal values

// With 'as const' — types are literal
const config = { env: 'prod', port: 3000 } as const;
// type: { readonly env: 'prod'; readonly port: 3000 }

// Derive union from object values:
const ROUTES = {
  home: '/',
  about: '/about',
  profile: '/profile',
} as const;
type Route = typeof ROUTES[keyof typeof ROUTES];
// Route = '/' | '/about' | '/profile'
// Adding a new route to ROUTES automatically updates Route!

// Readonly arrays:
const PERMISSIONS = ['read', 'write', 'delete'] as const;
type Permission = typeof PERMISSIONS[number];
// Permission = 'read' | 'write' | 'delete'

// ReadonlyArray prevents mutation:
function processItems(items: ReadonlyArray<string>) {
  items.push('new'); // ❌ Error: Property 'push' does not exist on ReadonlyArray
  return items.map(i => i.toUpperCase()); // ✅ non-mutating methods OK
}

// Deep readonly:
type DeepReadonly<T> = {
  readonly [K in keyof T]: T[K] extends object ? DeepReadonly<T[K]> : T[K];
};

// Discriminated union — the most powerful narrowing pattern
interface Square  { kind: 'square';  side: number; }
interface Circle  { kind: 'circle';  radius: number; }
interface Triangle{ kind: 'triangle'; base: number; height: number; }
type Shape = Square | Circle | Triangle;

function area(shape: Shape): number {
  switch (shape.kind) {
    case 'square':   return shape.side ** 2;           // narrowed to Square
    case 'circle':   return Math.PI * shape.radius ** 2; // narrowed to Circle
    case 'triangle': return 0.5 * shape.base * shape.height; // narrowed to Triangle
    default:
      const _never: never = shape; // ❌ compile error if a case is missing
      throw new Error('Unknown shape');
  }
}

// Custom type predicate — 'is' operator
interface ApiError { code: number; message: string; }
interface User { id: string; name: string; }
type ApiResult = User | ApiError;

function isError(result: ApiResult): result is ApiError {
  return 'code' in result && typeof result.code === 'number';
}

const result: ApiResult = await fetchUser();
if (isError(result)) {
  console.error(result.code, result.message); // narrowed to ApiError
} else {
  console.log(result.name); // narrowed to User
}

// Assertion functions — throw on wrong type:
function assertIsString(val: unknown): asserts val is string {
  if (typeof val !== 'string') throw new TypeError('Expected string');
}
assertIsString(input); // After this line, TS knows input is string

// 'satisfies' — validate without widening
type Colors = Record<string, string>;

// With type annotation — widened (loses literals)
const palette: Colors = {
  red: '#ff0000',
  green: '#00ff00',
};
palette.red.toUpperCase(); // Works but red is just 'string'

// With 'satisfies' — validated AND literal types preserved!
const palette = {
  red: '#ff0000',
  green: '#00ff00',
} satisfies Colors;
palette.red.toUpperCase(); // Works AND 'red' is typed as '#ff0000' (literal)
palette.unknownColor;      // ❌ Error! 'satisfies' validates the shape

// Assertion function — narrows permanently in the scope
function assertDefined<T>(val: T | null | undefined): asserts val is T {
  if (val == null) throw new Error('Expected defined value');
}

let user: User | null = getUser();
assertDefined(user);  // Throws if null
user.name;            // ✅ TS knows user is not null after this line
// No need for 'if (user)' on every usage

// Combine both for powerful validation:
const config = {
  env: process.env.NODE_ENV,
  port: Number(process.env.PORT),
} satisfies { env: string | undefined; port: number };
assertDefined(config.env); // env is now string, not string | undefined

