// Abstract class — defines interface, can't be instantiated
abstract class Animal {
  abstract makeSound(): string; // subclasses MUST implement
  abstract get name(): string;

  move(distance: number): void { // shared implementation
    console.log(`${this.name} moves ${distance}m`);
  }
}

class Dog extends Animal {
  get name() { return 'Dog'; }
  makeSound() { return 'Woof!'; } // must implement
}

new Animal(); // ❌ Cannot create instance of abstract class
new Dog();    // ✅

// Generic class
class Stack<T> {
  private items: T[] = [];
  push(item: T): void { this.items.push(item); }
  pop(): T | undefined { return this.items.pop(); }
  peek(): T | undefined { return this.items[this.items.length - 1]; }
}

const numStack = new Stack<number>();
numStack.push(1);  // ✅
numStack.push('a'); // ❌ string not assignable to number

// Legacy decorator (experimentalDecorators: true)
// --- Class Decorator ---
function Injectable(target: Function) {
  // Mark this class as dependency-injectable
  Reflect.defineMetadata('injectable', true, target);
}

// --- Method Decorator ---
function Log(target: any, key: string, descriptor: PropertyDescriptor) {
  const original = descriptor.value;
  descriptor.value = function(...args: any[]) {
    console.log(`[${key}] called with`, args);
    const result = original.apply(this, args);
    console.log(`[${key}] returned`, result);
    return result;
  };
  return descriptor;
}

// --- Property Decorator ---
function Required(target: any, propertyKey: string) {
  // Can use reflect-metadata to record required fields
  const fields: string[] = Reflect.getMetadata('required', target) || [];
  fields.push(propertyKey);
  Reflect.defineMetadata('required', fields, target);
}

// Usage (NestJS-style)
@Injectable()
class UserService {
  @Required
  private readonly db: Database;

  @Log
  async getUser(id: string): Promise<User> {
    return this.db.findUser(id);
  }
}

// TS 5.0+ Standard Decorators (new API):
function logged<T extends (...args: any[]) => any>(
  target: T,
  context: ClassMethodDecoratorContext
) {
  return function(...args: Parameters<T>): ReturnType<T> {
    console.log(`Calling ${String(context.name)}`);
    return target.apply(this, args);
  } as T;
}

