// Simple fluent builder
class QueryBuilder {
  private conditions: string[] = [];
  private limitValue?: number;

  where(condition: string): this {
    this.conditions.push(condition);
    return this; // return 'this' for chaining
  }

  limit(n: number): this {
    this.limitValue = n;
    return this;
  }

  build(): string {
    const where = this.conditions.length
      ? `WHERE ${this.conditions.join(' AND ')}`
      : '';
    const limit = this.limitValue ? `LIMIT ${this.limitValue}` : '';
    return `SELECT * FROM users ${where} ${limit}`.trim();
  }
}

const query = new QueryBuilder()
  .where('age > 18')
  .where('active = true')
  .limit(10)
  .build();

// Type-safe builder — build() only exists when required fields are set
type BuilderState = { name: boolean; email: boolean };

class UserBuilder<State extends BuilderState = { name: false; email: false }> {
  private data: Partial<User> = {};

  setName(name: string): UserBuilder<State & { name: true }> {
    this.data.name = name;
    return this as any;
  }

  setEmail(email: string): UserBuilder<State & { email: true }> {
    this.data.email = email;
    return this as any;
  }

  // build() only available when both name and email are set
  build(this: UserBuilder<{ name: true; email: true }>): User {
    return this.data as User;
  }
}

const user = new UserBuilder()
  .setName('Alice')
  .setEmail('alice@example.com')
  .build(); // ✅ Both set

new UserBuilder().setName('Alice').build(); // ❌ Compile error: email not set

// Result type — errors as values, not exceptions
type Ok<T>  = { success: true;  data: T };
type Err<E> = { success: false; error: E };
type Result<T, E = Error> = Ok<T> | Err<E>;

// Factory helpers
const ok  = <T>(data: T): Ok<T>   => ({ success: true, data });
const err = <E>(error: E): Err<E> => ({ success: false, error });

// Function that can fail — caller MUST handle both cases:
async function fetchUser(id: string): Promise<Result<User, 'NOT_FOUND' | 'NETWORK_ERROR'>> {
  try {
    const res = await fetch(`/api/users/${id}`);
    if (res.status === 404) return err('NOT_FOUND');
    if (!res.ok) return err('NETWORK_ERROR');
    return ok(await res.json());
  } catch {
    return err('NETWORK_ERROR');
  }
}

// Caller is forced to handle both:
const result = await fetchUser('123');
if (result.success) {
  console.log(result.data.name); // ✅ narrowed to Ok<User>
} else {
  // result.error is 'NOT_FOUND' | 'NETWORK_ERROR' — exhaustive handling:
  switch (result.error) {
    case 'NOT_FOUND': showNotFound(); break;
    case 'NETWORK_ERROR': showRetry(); break;
  }
}

// Option type — nullable without null
type Some<T> = { _tag: 'Some'; value: T };
type None   = { _tag: 'None' };
type Option<T> = Some<T> | None;

const some = <T>(value: T): Some<T> => ({ _tag: 'Some', value });
const none: None = { _tag: 'None' };

// Basic conditional type
type IsString<T> = T extends string ? 'yes' : 'no';
type A = IsString<string>; // 'yes'
type B = IsString<number>; // 'no'

// Distributive over unions — applied to EACH member:
type ToArray<T> = T extends any ? T[] : never;
type C = ToArray<string | number>;
// = string[] | number[] (not (string | number)[])

// Disable distributivity with tuple wrapper:
type ToArrayND<T> = [T] extends [any] ? T[] : never;
type D = ToArrayND<string | number>;
// = (string | number)[] — treated as one type

// infer — extract part of a matched type
type UnwrapArray<T> = T extends (infer U)[] ? U : T;
type E = UnwrapArray<string[]>;  // string
type F = UnwrapArray<number>;    // number (not an array)

type UnwrapPromise<T> = T extends Promise<infer U> ? UnwrapPromise<U> : T;
type G = UnwrapPromise<Promise<Promise<string>>>; // string (recursive!)

// Practical: get last element type of a tuple
type Last<T extends any[]> =
  T extends [...any[], infer L] ? L : never;
type H = Last<[string, number, boolean]>; // boolean

// Practical: function overload type selection
type PickByValue<T, V> = {
  [K in keyof T as T[K] extends V ? K : never]: T[K]
};
type StringProps = PickByValue<{ a: string; b: number; c: string }, string>;
// { a: string; c: string } — only string properties

// Mapped type basics
type Optional<T> = { [K in keyof T]?: T[K] };   // same as Partial
type Mutable<T>  = { -readonly [K in keyof T]: T[K] }; // remove readonly

// Key remapping with 'as'
type Getters<T> = {
  [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K];
};
type UserGetters = Getters<{ name: string; age: number }>;
// { getName: () => string; getAge: () => number }

// Filter keys with 'as ... never'
type OnlyStrings<T> = {
  [K in keyof T as T[K] extends string ? K : never]: T[K];
};
type A = OnlyStrings<{ id: number; name: string; email: string }>;
// { name: string; email: string }

// Template literal types — event system
type EventMap = {
  click: MouseEvent;
  keydown: KeyboardEvent;
  resize: UIEvent;
};
type EventListeners = {
  [K in keyof EventMap as `on${Capitalize<K>}`]: (event: EventMap[K]) => void;
};
// { onClick: (event: MouseEvent) => void; onKeydown: ...; onResize: ... }

// Deep partial:
type DeepPartial<T> = T extends object
  ? { [K in keyof T]?: DeepPartial<T[K]> }
  : T;

