// SLOW — recursive conditional type without bound:
type DeepReadonly<T> = {
  readonly [K in keyof T]: T[K] extends object ? DeepReadonly<T[K]> : T[K];
};
// On deeply nested objects, this explodes. TS may give up.

// BETTER — add a depth limit:
type DeepReadonly<T, Depth extends number = 5,
  Stack extends number[] = []> =
  Stack['length'] extends Depth
    ? T // stop recursing at depth limit
    : {
        readonly [K in keyof T]:
          T[K] extends object
            ? DeepReadonly<T[K], Depth, [0, ...Stack]>
            : T[K];
      };

